	if run.UnitsCertified != 90 {
		t.Errorf("UnitsCertified = %d, want 90", run.UnitsCertified)
	}
	if run.OverallGrade != "B+" {
		t.Errorf("OverallGrade = %q, want B+", run.OverallGrade)
	}
}

